<script setup lang="ts">import type {  AttachmentFileItem,  AttachmentPictureCardUploadProps,} from "@/types/composables/attachmentUpload.ts";import LAttachmentPreview from "@/components/attachment/AttachmentPreview.vue";import {ATTACHMENT_PREVIEW_MODE} from "@/constants/systemConstant.ts";import {useAttachmentUploadFiles} from "@/composables/attachment/useAttachmentUploadFiles.js";import {computed, useSlots} from "vue";import type {UploadChangeParam} from "antdv-next";defineOptions({  name: 'LAttachmentPictureCardUpload',})const props = withDefaults(defineProps<AttachmentPictureCardUploadProps>(), {  mode: ATTACHMENT_PREVIEW_MODE.PICTURE_CARD,  preview:false,  changeThumbUrl: true})const fileList = defineModel<AttachmentFileItem[]>('fileList', {default:() => []})const {uploadFiles} = useAttachmentUploadFiles(fileList)const slots = useSlots()const emit = defineEmits<{  change: [info: UploadChangeParam]}>()function onChange(info: UploadChangeParam) {  emit('change', info)}const uploadClasses = computed(() => ({  trigger: props.classes?.trigger,}))const uploadStyles = computed(() => ({  trigger: props.styles?.trigger,}))</script><template>  <div>    <l-attachment-preview      v-model:file-list="uploadFiles"      :preview="preview"      :classes="props.classes"      :styles="props.styles"      :mode="ATTACHMENT_PREVIEW_MODE.PICTURE_CARD"      :change-thumb-url="changeThumbUrl"    >      <template #pictureCardAfter v-if="!props.maxCount || uploadFiles.length < props.maxCount || props.preview">        <a-upload          v-bind="$attrs"          :classes="uploadClasses"          :styles="uploadStyles"          list-type="picture-card"          v-if="!preview"          v-model:file-list="uploadFiles"          :before-upload="() => false"          :show-upload-list="false"          :max-count="props.maxCount"          :multiple="props.multiple"          :accept="props.accept"          @change="onChange"        >          <a-space orientation="vertical">            <a-typography-text type="secondary">              <icon-font class="text-3xl" type="icon-add" />            </a-typography-text>            <slot name="uploadDescription" />            <a-typography-text  type="secondary" v-if="props.maxCount && props.maxCount > 1">              {{ uploadFiles.length }} / {{ props.maxCount }}            </a-typography-text>          </a-space>        </a-upload>      </template>      <template v-if="slots.itemRender" #itemRender="{file}">        <slot name="itemRender" :file="file" />      </template>      <template #itemTitle="{file}" v-if="slots.itemTitle" >        <slot name="itemTitle" :file="file" />      </template>      <template #itemDescription="{file}" v-if="slots.itemDescription">        <slot name="itemDescription" :file="file" />      </template>    </l-attachment-preview>  </div></template>